  ('social-worker-moex-01801', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列那一個概念是班杜拉（Bandura）的社會學習理論所提出，用來表達當一個留學生到了陌生的城市讀 書，在沒有支持系統的情況下，靠著信念或期望，有助其適應新環境與新角色，並在面對挫折或失敗經 驗時能堅持或調適？', '["自我效能（self-efficacy）", "復原力（resilience）", "充權（empowerment）", "動機（motivation）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "0f97a01c1698", "answer_pdf_sha1": "501bbd54e4d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
