  ('social-worker-moex-01803', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '世界衛生組織對「活躍老化」的定義為「將健康、參與、安全機會的極大化，目標是讓人在老化過程中， 強化生活品質」。但有理論提出：「期望老年人（older adults）充分活躍其社會角色是不切實際的想法， 年紀大的人，應從其角色或活動中撤退或減少活動參與量。」以上敘述屬於那一個理論？', '["活動理論（Activity theory）", "脫離理論（Disengagement theory）", "連續理論（Continuity theory）", "老化理論（Ageing theory）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "0f97a01c1698", "answer_pdf_sha1": "501bbd54e4d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
