  ('social-worker-moex-01805', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '愛滋病（AIDS）是一種後天免疫缺乏症候群，社會上對愛滋病仍存有如生活不檢點等刻板印象。下列敘 述何者屬刻板印象？', '["愛滋病通常發生在擁有複雜性關係的男同志身上", "愛滋病的潛伏期有可能長達10年以上之久", "愛滋病毒主要經由血液、體液及尿液傳染", "愛滋病毒對性生活活躍又未採取安全措施的人風險較高"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "0f97a01c1698", "answer_pdf_sha1": "501bbd54e4d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
